import numpy as np
def update_edge_distance(edge_distance, local_opt_tour, edge_n_used):
    updated_edge_distance = edge_distance.copy()
    penalty_base = 1.0
    reward_base = 0.1
    adjustment_rate = 0.5
    maximum_usage = np.max(edge_n_used) + 1e-5
    dynamic_weights = edge_n_used / maximum_usage
    num_cities = len(local_opt_tour)
    successful_perturbations = {}
    for i in range(num_cities):
        city_from = local_opt_tour[i]
        city_to = local_opt_tour[(i + 1) % num_cities]
        penalty = penalty_base * (1 - dynamic_weights[city_from, city_to])
        updated_edge_distance[city_from, city_to] += penalty
        updated_edge_distance[city_to, city_from] += penalty
        if (city_from, city_to) not in successful_perturbations:
            successful_perturbations[(city_from, city_to)] = 0
        successful_perturbations[(city_from, city_to)] += 1
    for i in range(len(edge_distance)):
        for j in range(len(edge_distance)):
            if edge_n_used[i, j] == 0 and (i, j) not in successful_perturbations:
                updated_edge_distance[i, j] = max(updated_edge_distance[i, j] - reward_base, 0)
            elif (i, j) in successful_perturbations:
                updated_edge_distance[i, j] *= (1 - adjustment_rate * successful_perturbations[(i, j)] / num_cities)
    return updated_edge_distance

